// 10-todom-parsedom.js
// toDOM and parseDOM: the round-trip between ProseMirror docs and HTML.
//
// This example defines a custom schema with:
//   - A "note" node that renders as <div class="note">
//   - A "highlight" mark that renders as <span style="background:yellow">
//   - A heading node with getAttrs that extracts the level from h1–h6
//
// The info panel below the editor shows the live HTML output, generated by
// DOMSerializer.fromSchema(schema).serializeFragment(doc.content).

import { EditorState } from "prosemirror-state";
import { EditorView } from "prosemirror-view";
import { Schema, DOMSerializer } from "prosemirror-model";
import { keymap } from "prosemirror-keymap";
import { baseKeymap } from "prosemirror-commands";
import { undo, redo, history } from "prosemirror-history";

// ── Schema: every toDOM / parseDOM is annotated ────────────────

const mySchema = new Schema({
  nodes: {
    doc: { content: "block+" },

    // --- Paragraph: the simplest toDOM/parseDOM pair ---
    // toDOM: ["p", 0] means "render as <p> and put content inside it."
    // parseDOM: [{ tag: "p" }] means "when you see a <p>, treat it as this node."
    paragraph: {
      group: "block",
      content: "inline*",
      toDOM() { return ["p", 0]; },
      parseDOM: [{ tag: "p" }],
    },

    // --- Heading: uses getAttrs to extract the level from the tag name ---
    // toDOM is dynamic — it reads node.attrs.level to pick h1, h2, etc.
    // parseDOM uses .map() to create one rule per heading level.
    // Each rule sets `attrs: { level }` so the parser knows which level it is.
    heading: {
      group: "block",
      content: "inline*",
      attrs: { level: { default: 1 } },
      // Dynamic tag: "h1", "h2", etc. based on the level attribute.
      toDOM(node) { return ["h" + node.attrs.level, 0]; },
      // One parse rule per level. getAttrs returns the level as an attribute.
      // This is equivalent to writing out six separate { tag: "h1", attrs: ... } rules.
      parseDOM: [1, 2, 3, 4, 5, 6].map(level => ({
        tag: "h" + level,
        // getAttrs receives the DOM element; here we just return the known level.
        getAttrs(dom) { return { level }; },
      })),
    },

    // --- Note: a custom block node with a CSS class ---
    // toDOM: ["div", { class: "note" }, 0] — renders as <div class="note">
    //   - The second argument is an attributes object (HTML attrs, not PM attrs).
    //   - The 0 is the content hole where child nodes go.
    // parseDOM: uses getAttrs to only match <div> elements that have class "note".
    //   Without getAttrs, every <div> would be parsed as a note!
    note: {
      group: "block",
      content: "block+",
      toDOM() { return ["div", { class: "note" }, 0]; },
      parseDOM: [{
        tag: "div",
        // getAttrs acts as a filter: return false to reject the match.
        // Only <div class="note"> becomes a note node.
        getAttrs(dom) {
          return dom.classList.contains("note") ? {} : false;
        },
      }],
    },

    text: { group: "inline", inline: true },
  },

  marks: {
    // --- Strong: straightforward mark ---
    strong: {
      toDOM() { return ["strong", 0]; },
      parseDOM: [
        { tag: "strong" },
        { tag: "b" },
        // Also match CSS font-weight. getAttrs returns false for "normal"
        // so that font-weight:normal doesn't accidentally become bold.
        {
          style: "font-weight",
          getAttrs(value) {
            return /^(bold|[7-9]\d{2,})$/.test(value) ? {} : false;
          },
        },
      ],
    },

    // --- Emphasis: matches <em>, <i>, and italic CSS ---
    em: {
      toDOM() { return ["em", 0]; },
      parseDOM: [
        { tag: "em" },
        { tag: "i" },
        { style: "font-style=italic" },
      ],
    },

    // --- Highlight: a custom mark using inline styles ---
    // toDOM: renders as <span style="background:yellow">
    // parseDOM: matches any <span> with a yellow background, plus the
    //   CSS style "background-color=yellow" for pasted content.
    highlight: {
      toDOM() { return ["span", { style: "background:yellow" }, 0]; },
      parseDOM: [
        {
          tag: "span",
          getAttrs(dom) {
            // Only match <span> elements that have a yellow background
            return /yellow/.test(dom.style.background) ? {} : false;
          },
        },
        { style: "background-color=yellow" },
      ],
    },
  },
});

// ── Build the initial document programmatically ────────────────

const initDoc = mySchema.node("doc", null, [
  mySchema.node("heading", { level: 1 }, [
    mySchema.text("toDOM & parseDOM Demo"),
  ]),
  mySchema.node("paragraph", null, [
    mySchema.text("This editor uses a custom schema. Edit the text and "),
    mySchema.text("watch the HTML output", [mySchema.marks.strong.create()]),
    mySchema.text(" update in the panel below."),
  ]),
  mySchema.node("heading", { level: 2 }, [
    mySchema.text("A note block"),
  ]),
  // The "note" node — rendered as <div class="note">
  mySchema.node("note", null, [
    mySchema.node("paragraph", null, [
      mySchema.text("This paragraph is inside a "),
      mySchema.text("note", [mySchema.marks.strong.create()]),
      mySchema.text(" node, rendered as "),
      mySchema.text('<div class="note">', [mySchema.marks.em.create()]),
      mySchema.text("."),
    ]),
  ]),
  mySchema.node("paragraph", null, [
    mySchema.text("Here is some "),
    mySchema.text("highlighted text", [mySchema.marks.highlight.create()]),
    mySchema.text(" using the custom highlight mark."),
  ]),
]);

// ── Editor state and view ──────────────────────────────────────

const state = EditorState.create({
  doc: initDoc,
  plugins: [
    history(),
    keymap({ "Mod-z": undo, "Mod-Shift-z": redo }),
    keymap(baseKeymap),
  ],
});

// ── Style for the note block (injected into the page) ──────────

const styleEl = document.createElement("style");
styleEl.textContent = `
  .note {
    background: #fff8e1;
    border-left: 4px solid #ffc107;
    padding: 8px 12px;
    margin: 8px 0;
    border-radius: 2px;
  }
`;
document.head.appendChild(styleEl);

// ── Info panel: shows serialized HTML output ───────────────────

const infoEl = document.createElement("pre");
infoEl.style.cssText =
  "margin:12px 0;padding:12px;background:#f0f4f8;border:1px solid #c0d0e0;" +
  "font-size:12px;max-height:400px;overflow:auto;line-height:1.5;" +
  "white-space:pre-wrap;word-break:break-word;";
document.querySelector("#editor").parentNode.appendChild(infoEl);

// Use DOMSerializer to convert the document to real HTML.
// This is exactly what the editor does internally to render content.
const serializer = DOMSerializer.fromSchema(mySchema);

function updateInfo(view) {
  const { doc } = view.state;

  // serializeFragment returns a DocumentFragment (a real DOM node).
  // We put it in a temporary <div> to read its .innerHTML.
  const fragment = serializer.serializeFragment(doc.content);
  const wrapper = document.createElement("div");
  wrapper.appendChild(fragment);

  // Pretty-print the HTML with basic indentation
  const raw = wrapper.innerHTML;
  const pretty = prettyHTML(raw);

  const lines = [];
  lines.push("=== SERIALIZED HTML (from DOMSerializer) ===\n");
  lines.push(pretty);
  lines.push("\n\n=== SCHEMA toDOM SPECS ===\n");
  lines.push("paragraph   -> [\"p\", 0]");
  lines.push("heading     -> [\"h\" + level, 0]");
  lines.push("note        -> [\"div\", { class: \"note\" }, 0]");
  lines.push("strong      -> [\"strong\", 0]");
  lines.push("em          -> [\"em\", 0]");
  lines.push("highlight   -> [\"span\", { style: \"background:yellow\" }, 0]");

  infoEl.textContent = lines.join("\n");
}

// Minimal HTML pretty-printer: adds newlines and indentation around tags.
function prettyHTML(html) {
  let result = "";
  let indent = 0;
  // Split on tag boundaries, keeping the tags
  const tokens = html.split(/(<\/?[^>]+>)/g).filter(Boolean);
  for (const token of tokens) {
    if (token.startsWith("</")) {
      // Closing tag — decrease indent, then print
      indent = Math.max(0, indent - 1);
      result += "  ".repeat(indent) + token + "\n";
    } else if (token.startsWith("<") && !token.endsWith("/>")) {
      // Opening tag — print, then increase indent
      result += "  ".repeat(indent) + token + "\n";
      indent++;
    } else if (token.startsWith("<")) {
      // Self-closing tag
      result += "  ".repeat(indent) + token + "\n";
    } else {
      // Text content
      result += "  ".repeat(indent) + token + "\n";
    }
  }
  return result.trimEnd();
}

// ── Create the view ────────────────────────────────────────────

const view = new EditorView(document.querySelector("#editor"), {
  state,
  dispatchTransaction(tr) {
    const newState = this.state.apply(tr);
    this.updateState(newState);
    updateInfo(this);
  },
});

// Initial render of the info panel
updateInfo(view);

// ────────────────────────────────────────────────────────────────
// Exercises:
//   1. Edit the text in the editor. Watch the HTML panel update live.
//      Notice how <div class="note"> wraps the note block's content.
//
//   2. Look at the heading's toDOM: it uses node.attrs.level to pick the
//      tag. Try changing { level: 2 } to { level: 3 } in initDoc above
//      and see the HTML change from <h2> to <h3>.
//
//   3. The highlight mark's parseDOM uses getAttrs to check for a yellow
//      background. What happens if you change the style to "background:cyan"
//      in toDOM? (The mark still works — but pasted yellow highlights
//      won't round-trip anymore.)
//
//   4. Try removing the getAttrs filter from the note's parseDOM. Now
//      every <div> pasted into the editor would become a note node!
//      getAttrs: returning false is how you reject a match.
//
//   5. Add a new mark called "code" that renders as <code> and parses
//      from <code> tags. Apply it to some text in initDoc.
